import{_ as a,o,c as t,ai as r}from"./chunks/framework.BIXs0jTs.js";const l="/assets/preface-cover.Balx8Fq4.png",g=JSON.parse('{"title":"实战三：遗留系统改造与渐进重构","description":"","frontmatter":{"title":"实战三：遗留系统改造与渐进重构"},"headers":[],"relativePath":"40-practices/legacy-refactor.md","filePath":"40-practices/legacy-refactor.md","lastUpdated":null}'),c={name:"40-practices/legacy-refactor.md"};function d(i,e,s,n,p,h){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="第-14-章-实战三-遗留系统改造与渐进重构" tabindex="-1">第 14 章　实战三：遗留系统改造与渐进重构 <a class="header-anchor" href="#第-14-章-实战三-遗留系统改造与渐进重构" aria-label="Permalink to &quot;第 14 章　实战三：遗留系统改造与渐进重构&quot;">​</a></h1><p><img src="'+l+'" alt="实战：遗留系统重构与现代化"></p><p>每个程序员都梦想着从零开始写代码（Greenfield），但现实是，我们 80% 的时间都在和遗留代码（Legacy Code）打交道。</p><p>遗留代码通常意味着：没有文档、测试覆盖率低、变量命名像天书、原作者早已离职。</p><p>幸运的是，Claude Code 是对付遗留代码的神器。它不嫌弃代码乱，而且能瞬间读完几千行代码。本章将展示如何利用 Claude 进行安全的渐进式重构。</p><h2 id="_14-1-遗留系统盘点" tabindex="-1">14.1 遗留系统盘点 <a class="header-anchor" href="#_14-1-遗留系统盘点" aria-label="Permalink to &quot;14.1 遗留系统盘点&quot;">​</a></h2><p>接手一个老项目的第一步，是搞清楚“它到底在干什么”。</p><h3 id="_14-1-1-利用-ask-mode-绘制地图" tabindex="-1">14.1.1 利用 Ask Mode 绘制地图 <a class="header-anchor" href="#_14-1-1-利用-ask-mode-绘制地图" aria-label="Permalink to &quot;14.1.1 利用 Ask Mode 绘制地图&quot;">​</a></h3><p>不要直接开始读代码。先用 <code>Ask Mode</code> 进行全局扫描。</p><blockquote><p><strong>User</strong>: “扫描 <code>src/legacy/billing</code> 目录。解释一下计费逻辑的主要流程。绘制一个 Mermaid 时序图。”</p></blockquote><p>Claude 会阅读相关文件，总结出业务流程：</p><ol><li>用户下单 -&gt; <code>processOrder()</code></li><li>计算折扣 -&gt; <code>calc_disc_v2()</code> (注意这个 v2，暗示有历史包袱)</li><li>扣减库存 -&gt; <code>update_stock_final()</code></li></ol><h3 id="_14-1-2-识别-坏味道-code-smells" tabindex="-1">14.1.2 识别“坏味道” (Code Smells) <a class="header-anchor" href="#_14-1-2-识别-坏味道-code-smells" aria-label="Permalink to &quot;14.1.2 识别“坏味道” (Code Smells)&quot;">​</a></h3><p>让 Claude 帮你找出最需要重构的地方。</p><blockquote><p><strong>User</strong>: “分析 <code>OrderManager.java</code>。指出其中复杂度最高、最难维护的方法，并说明原因。”</p></blockquote><p>Claude 可能会指出：</p><ul><li><code>calculateTotal</code> 方法有 500 行，包含 20 个 <code>if-else</code>。</li><li>存在大量的魔法数字（Magic Numbers）。</li><li>数据库操作和业务逻辑混杂在一起。</li></ul><h2 id="_14-2-设计渐进式重构方案" tabindex="-1">14.2 设计渐进式重构方案 <a class="header-anchor" href="#_14-2-设计渐进式重构方案" aria-label="Permalink to &quot;14.2 设计渐进式重构方案&quot;">​</a></h2><p>重构最怕的是“步子迈太大，扯着蛋”。我们需要制定一个安全的计划。</p><h3 id="_14-2-1-建立安全网-补充测试" tabindex="-1">14.2.1 建立安全网：补充测试 <a class="header-anchor" href="#_14-2-1-建立安全网-补充测试" aria-label="Permalink to &quot;14.2.1 建立安全网：补充测试&quot;">​</a></h3><p><strong>黄金法则</strong>：在修改遗留代码之前，必须先有测试。</p><p>如果现在的代码没有测试，先让 Claude 写。</p><blockquote><p><strong>User</strong>: “我要重构 <code>calculateTotal</code> 方法。请先为它编写一组单元测试，覆盖主要的分支逻辑。不要修改原代码，只写测试。”</p></blockquote><p>Claude 会生成测试用例。运行这些测试，确保它们通过（也就是捕捉到了当前的行文，哪怕是错误的行文，也要先“固化”下来）。</p><h3 id="_14-2-2-绞杀植物模式-strangler-fig-pattern" tabindex="-1">14.2.2 绞杀植物模式 (Strangler Fig Pattern) <a class="header-anchor" href="#_14-2-2-绞杀植物模式-strangler-fig-pattern" aria-label="Permalink to &quot;14.2.2 绞杀植物模式 (Strangler Fig Pattern)&quot;">​</a></h3><p>不要一次性重写整个类。我们可以用“绞杀植物模式”，逐步替换。</p><ol><li><strong>创建新接口</strong>：定义一个干净的 <code>IPricingService</code>。</li><li><strong>实现新逻辑</strong>：让 Claude 根据旧代码的逻辑，写一个新的实现类，使用现代的写法（比如策略模式代替 <code>if-else</code>）。</li><li><strong>灰度切换</strong>：在旧代码中调用新接口。</li></ol><h2 id="_14-3-执行与验证" tabindex="-1">14.3 执行与验证 <a class="header-anchor" href="#_14-3-执行与验证" aria-label="Permalink to &quot;14.3 执行与验证&quot;">​</a></h2><p>现在开始动手。</p><h3 id="_14-3-1-提取函数-extract-method" tabindex="-1">14.3.1 提取函数 (Extract Method) <a class="header-anchor" href="#_14-3-1-提取函数-extract-method" aria-label="Permalink to &quot;14.3.1 提取函数 (Extract Method)&quot;">​</a></h3><p>这是最安全的重构手法。</p><blockquote><p><strong>User</strong>: “在 <code>OrderManager.java</code> 中，将 <code>calculateTotal</code> 方法里处理‘VIP 折扣’的 50 行代码提取为一个独立的方法 <code>calculateVipDiscount</code>。”</p></blockquote><p>Claude 会自动处理变量的作用域，完成提取。</p><h3 id="_14-3-2-重命名变量-rename-variable" tabindex="-1">14.3.2 重命名变量 (Rename Variable) <a class="header-anchor" href="#_14-3-2-重命名变量-rename-variable" aria-label="Permalink to &quot;14.3.2 重命名变量 (Rename Variable)&quot;">​</a></h3><p>把 <code>a</code>, <code>b</code>, <code>tmp</code> 变成有意义的名字。</p><blockquote><p><strong>User</strong>: “将 <code>int d</code> 重命名为 <code>discountRate</code>，将 <code>float p</code> 重命名为 <code>finalPrice</code>。”</p></blockquote><h3 id="_14-3-3-转换技术栈" tabindex="-1">14.3.3 转换技术栈 <a class="header-anchor" href="#_14-3-3-转换技术栈" aria-label="Permalink to &quot;14.3.3 转换技术栈&quot;">​</a></h3><p>有时你需要把代码从一种语言迁移到另一种（例如 Java -&gt; Go，或 jQuery -&gt; React）。</p><blockquote><p><strong>User</strong>: “读取 <code>frontend/old-script.js</code>。将其中的 DOM 操作逻辑重写为 React 组件。保持 CSS 类名不变。”</p></blockquote><p>Claude 能够理解逻辑并进行“翻译”，而不仅仅是语法转换。</p><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>重构遗留系统就像拆弹。Claude Code 是你的拆弹专家：</p><ol><li><strong>它能看懂</strong>：快速理解复杂逻辑。</li><li><strong>它能防爆</strong>：帮你编写测试用例作为安全网。</li><li><strong>它手很稳</strong>：自动化执行重构操作，避免人为的拼写错误。</li></ol><p>通过这三步——<strong>理解、加固、重构</strong>，你可以把任何一座“屎山”逐步改造成现代化的代码堡垒。</p><p>至此，我们的技术实战部分全部结束。最后一章，我们将聊聊<strong>人</strong>的问题——如何在团队中推广这些工具。</p>',45)])])}const _=a(c,[["render",d]]);export{g as __pageData,_ as default};
